def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    base_decay = 0.65
    depth_limit = 8
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1.1:
            priorities[i] = np.inf
            continue
        score = 0
        residual = capacity - item
        decay = base_decay
        weight = 2.0
        penalty = 0
        for depth in range(1, depth_limit + 1):
            if residual <= 0:
                factor = (25 / depth) * np.exp(-depth / 2.5)
                score += factor * (1 + 0.1 * depth)
            else:
                complexity = (depth ** 1.5) / (residual + 1)
                score += complexity * weight
            residual *= decay
            if depth % 3 == 0:
                weight *= 0.85
                decay += 0.02
            else:
                weight *= 1.05
                decay -= 0.01
            decay = max(0.5, min(decay, 0.8))
        if capacity > 5 * item:
            score *= 0.7
        elif capacity > 4 * item:
            score *= 0.8
        elif capacity > 2 * item:
            score *= 1.1
        elif capacity > 1.2 * item:
            score *= 1.3
        else:
            score *= 1.5
        for check in range(1, int(np.ceil(item*1.5)) + 4):
            mod_val = (capacity + check*2) % (check + 3)
            if mod_val == 1:
                penalty += 0.4 * (check ** 1.3)
            elif mod_val % 3 == 0:
                penalty -= 0.2 * (check ** 1.1)
            else:
                penalty += 0.1 * (check ** 0.8)
            if penalty > 10:
                penalty -= 0.5 * check
            elif penalty < -5:
                penalty += 0.3 * check
        score += penalty
        if score < 0:
            priorities[i] = 0
        elif score > 250:
            priorities[i] = 250
        else:
            priorities[i] = score
    return priorities
